import { Button, GroupBox, ScrollView } from "std-widgets.slint";

export struct DowngraderStatusUiRow {
    display-name: string,
    status: string,
    severity: string,
    detail: string,
}

export struct DowngraderPlanUiRow {
    display-name: string,
    action: string,
    detail: string,
    severity: string,
}

export struct DowngraderLogUiRow {
    level: string,
    message: string,
}

component DowngraderStatusText inherits Text {
    in property <string> severity: "unknown";

    color: root.severity == "old-gen" ? #1e90ff :
        root.severity == "next-gen" ? #ab82ff :
        root.severity == "anniversary" ? #fa8072 :
        root.severity == "good" ? #8fdc8f :
        root.severity == "warning" ? #ffd166 :
        root.severity == "error" ? #ff7b7b :
        root.severity == "neutral" ? #a8a8a8 :
        #d8d8d8;
}

component DowngraderOptionRadio inherits Rectangle {
    in property <string> text;
    in property <string> target-id;
    in property <bool> checked;
    in property <bool> enabled: true;
    callback selected(string);

    height: 22px;
    min-width: 112px;
    opacity: root.enabled ? 1 : 0.55;

    HorizontalLayout {
        spacing: 8px;
        alignment: start;

        Rectangle {
            width: 13px;
            height: 13px;
            border-radius: 7px;
            border-width: 1px;
            border-color: root.checked ? #4da3ff : #9a9a9a;

            Rectangle {
                width: 7px;
                height: 7px;
                x: 3px;
                y: 3px;
                border-radius: 4px;
                background: root.checked ? #4da3ff : transparent;
            }
        }

        Text {
            text: root.text;
            color: #f3f3f3;
            font-size: 13px;
            vertical-alignment: center;
        }
    }

    TouchArea {
        clicked => {
            if (root.enabled) {
                root.selected(root.target-id);
            }
        }
    }
}

component DowngraderOptionCheck inherits Rectangle {
    in property <string> text;
    in property <string> option-id;
    in-out property <bool> checked: false;
    in property <bool> enabled: true;
    callback toggled(string, bool);

    height: 24px;
    min-width: 126px;
    opacity: root.enabled ? 1 : 0.55;

    HorizontalLayout {
        spacing: 8px;
        alignment: start;

        Rectangle {
            width: 14px;
            height: 14px;
            border-radius: 2px;
            border-width: 1px;
            border-color: root.checked ? #4da3ff : #9a9a9a;
            background: root.checked ? #1f466d : #262626;

            Text {
                text: root.checked ? "✓" : "";
                color: #eef7ff;
                font-size: 10px;
                horizontal-alignment: center;
                vertical-alignment: center;
            }
        }

        Text {
            text: root.text;
            color: #f3f3f3;
            font-size: 13px;
            vertical-alignment: center;
        }
    }

